# iterative function
def f_iterative(n):
    return n if n < 3 else f_iterative_impl(2, 1, 0, n - 2)

def f_iterative_impl(a, b, c, count):
    return a if count == 0 else f_iterative_impl(a + 2 * b + 3 * c, a, b, count - 1)

# recursive function
def f_recursive(n):
    return (n if n < 3
            else f_recursive(n - 1)
                 + 2 * f_recursive(n - 2)
                 + 3 * f_recursive(n - 3))

def pascal_triangle(row, index):
    return (False if index > row
            else 1 if index == 1 or index == row
            else pascal_triangle(row - 1, index - 1)
                 + pascal_triangle(row - 1, index))

